create table if not exists products(product_id text primary key,name text not null,price numeric default 0,stripe_payment_link text,delivery_url text,active boolean default true,bundle_group text,updated_at timestamptz default now());
create table if not exists tickets(ticket_id text primary key,customer_email text not null,subject text not null,message text not null,status text default 'open',resolution text,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists reviews(review_id text primary key,customer_email text not null,customer_name text,product_id text,rating integer check(rating between 1 and 5),review_text text not null,status text default 'pending',created_at timestamptz default now());
create table if not exists licenses(license_id text primary key,name text not null,description text,permissions text,restrictions text,active boolean default true,updated_at timestamptz default now());
create table if not exists commissions(commission_id text primary key,affiliate_id text,gross_amount numeric default 0,commission_amount numeric default 0,status text default 'pending',paid_at timestamptz);
create table if not exists audit(audit_id text primary key,actor text,action text,entity_type text,entity_id text,details jsonb default '{}'::jsonb,created_at timestamptz default now());
alter table products enable row level security; alter table tickets enable row level security; alter table reviews enable row level security; alter table licenses enable row level security; alter table commissions enable row level security; alter table audit enable row level security;
create policy "read products" on products for select using(active=true); create policy "submit tickets" on tickets for insert with check(true); create policy "submit reviews" on reviews for insert with check(true);